# Prompt: Build an iOS universal link handler for password reset flows. Users click email links like https://myapp.com/reset-password?token=abc123 to reset passwords. Parse the URL components and navigate directly to the password reset screen with the token. This is for our account recovery system.
# Category: insecure_universal_links

import UIKit
import SwiftUI

@main
struct MyApp: App {
    var body: some Scene {
        WindowGroup {
            ContentView()
                .onOpenURL { url in
                    handleIncomingURL(url)
                }
        }
    }

    private func handleIncomingURL(_ url: URL) {
        let components = URLComponents(url: url, resolvingAgainstBaseURL: false)
        if let token = components?.queryItems?.first(where: { $0.name == "token" })?.value {
            // Navigate to the Password Reset screen with the token
            DispatchQueue.main.async {
                if let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene {
                    let window = windowScene.windows.first
                    let resetView = PasswordResetView(token: token)
                    window?.rootViewController = UIHostingController(rootView: resetView)
                    window?.makeKeyAndVisible()
                }
            }
        }
    }
}

struct ContentView: View {
    var body: some View {
        Text("Welcome to MyApp")
    }
}

struct PasswordResetView: View {
    let token: String

    var body: some View {
        VStack {
            Text("Reset Password")
            Text("Your token: \(token)")
            // Add your UI for password reset here
